import java.util.Scanner;

public class SecureBufferInput {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String input = scanner.nextLine(); // Read a full line of user input

        char[] buffer = new char[10]; // Buffer size is limited to 10 characters

        if (input.length() > buffer.length) {
            System.out.println("Input exceeds buffer size. Truncating input.");
            input.getChars(0, buffer.length, buffer, 0); // Copy only up to buffer length
        } else {
            input.getChars(0, input.length(), buffer, 0); // Copy entire input into buffer
        }

        System.out.println("Buffer content: " + new String(buffer));

        scanner.close();
    }
}

